SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_fin_tax_dep (tax_date, tax_seq, id_card, prename, memname, memsurname, paid_amount, tax_amount, deposit_account_no, deposit_type_code, seq_no) AS SELECT VIEW_REP_PAID_TAX.working_day AS TAX_DATE
  ,row_number() OVER () AS TAX_SEQ
  ,sc_mem_m_membership_registered.id_card AS ID_CARD
  ,CASE WHEN  coalesce(sc_dep_m_creditor.deposit_objective::text, '') = '' THEN  sc_mem_m_ucf_prename.prename   ELSE '-' END   AS PRENAME
  ,CASE WHEN  coalesce(sc_dep_m_creditor.deposit_objective::text, '') = '' THEN  sc_mem_m_membership_registered.member_name   ELSE sc_dep_m_creditor.deposit_objective END  AS MEMNAME   
  ,CASE WHEN  coalesce(sc_dep_m_creditor.deposit_objective::text, '') = '' THEN  sc_mem_m_membership_registered.member_surname   ELSE '' END   AS MEMSURNAME
  ,VIEW_REP_PAID_TAX.OP_INT AS PAID_AMOUNT
  ,VIEW_REP_PAID_TAX.OP_TAX AS TAX_AMOUNT
  
  ,sc_dep_m_creditor.deposit_account_no AS DEPOSIT_ACCOUNT_NO
  ,sc_dep_m_creditor.deposit_type_code AS DEPOSIT_TYPE_CODE
  ,VIEW_REP_PAID_TAX.seq_no AS SEQ_NO
    FROM VIEW_REP_PAID_TAX,   
         sc_dep_m_creditor,   
         sc_mem_m_membership_registered,   
         sc_mem_m_ucf_prename  
   WHERE ( VIEW_REP_PAID_TAX.deposit_account_no = sc_dep_m_creditor.deposit_account_no ) and ( sc_dep_m_creditor.membership_no = sc_mem_m_membership_registered.membership_no ) and ( sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code )   
and VIEW_REP_PAID_TAX.OP_TAX > 0          
--AND VIEW_REP_PAID_TAX.working_day ='24/5/2023'
 
ORDER BY VIEW_REP_PAID_TAX.working_day ASC,   
         sc_mem_m_membership_registered.id_card ASC,   
         sc_dep_m_creditor.deposit_account_no ASC,   
         VIEW_REP_PAID_TAX.seq_no ASC;

